 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { runPmAgent } from "../../agents/pm/agent";
 4→import { requireToolContext } from "./helpers";
 5→import type { ChatAgentToolDeps } from "./types";
 6→
 7→export function createInvokePmAgentTool(deps: ChatAgentToolDeps) {
 8→  return tool({
 9→    description:
10→      "Invoke the PM subagent — the single authority on tasks, features, and project status.",
11→    inputSchema: z.object({
12→      intent: z
13→        .enum(["plan_work", "check_status", "organize", "track_dependencies"])
14→        .describe(
15→          "plan_work: user discusses goals, features, or work to be done. check_status: user asks about progress, blockers, or project status. organize: user wants to restructure or re-prioritize. track_dependencies: user asks about blocked items or dependency chains.",
16→        ),
17→      context: z.string().min(1).describe("Conversation context for the PM agent"),
18→      project: z.string().optional().describe("Optional project scope"),
19→    }),
20→    execute: async (input, options) => {
