 1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
 2→import { Surreal } from "surrealdb";
 3→import type { ServerConfig } from "./config";
 4→
 5→export async function createRuntimeDependencies(config: ServerConfig): Promise<{
 6→  surreal: Surreal;
 7→  chatAgentModel: any;
 8→  extractionModel: any;
 9→  pmAgentModel: any;
10→  embeddingModel: any;
11→}> {
12→  const surreal = new Surreal();
13→  await surreal.connect(config.surrealUrl);
14→  await surreal.signin({ username: config.surrealUsername, password: config.surrealPassword });
15→  await surreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
16→
17→  const openrouter = createOpenRouter({ apiKey: config.openRouterApiKey });
18→  const chatAgentModel = openrouter(config.chatAgentModelId, {
19→    plugins: [{ id: "response-healing" }],
20→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
21→  });
22→  const extractionModel = openrouter(config.extractionModelId, {
23→    plugins: [{ id: "response-healing" }],
24→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
25→  });
26→  const pmAgentModel = openrouter(config.pmAgentModelId, {
27→    plugins: [{ id: "response-healing" }],
28→    ...(config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
29→  });
30→  const embeddingModel = openrouter.textEmbeddingModel(config.embeddingModelId);
31→
32→  return {
33→    surreal,
34→    chatAgentModel,
35→    extractionModel,
36→    pmAgentModel,
37→    embeddingModel,
38→  };
39→}
