 15→  possible_duplicate: z
 16→    .object({
 17→      id: z.string().min(1),
 18→      name: z.string().min(1),
 19→      similarity: z.number().min(0).max(1),
 20→    })
 21→    .optional(),
 22→});
 23→
 24→const pmAgentResultSchema = z.object({
 25→  summary: z.string().min(1),
 26→  suggestions: z.array(workItemSuggestionSchema),
 27→  updated: z.array(
 28→    z.object({
 29→      existing_id: z.string().min(1),
 30→      title: z.string().min(1),
 31→      changes: z.string().min(1),
 32→    }),
 33→  ),
 34→  discarded: z.array(
 35→    z.object({
