 59→const INTENT_INSTRUCTIONS: Record<PmAgentInput["intent"], string> = {
 60→  check_status: "Primary action: call get_project_status when a project scope is available.",
 61→  plan_work: "Primary action: propose tasks/features/projects with suggest_work_items or create_work_item, deduping each item.",
