 66→export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
 67→  const system = await buildPmSystemPrompt({
 68→    surreal: input.deps.surreal,
 69→    workspaceRecord: input.context.workspaceRecord,
 70→  });
 71→
 72→  const agent = new ToolLoopAgent({
 73→    id: "pm-agent",
 74→    model: input.deps.pmAgentModel,
 75→    instructions: system,
 76→    tools: createPmTools(input.deps),
 77→    output: Output.object({ schema: pmAgentResultSchema }),
 78→    experimental_context: input.context,
 79→    stopWhen: stepCountIs(6),
 80→  });
 81→
 82→  const result = await agent.generate({
 83→    prompt: [
 84→      "You are handling a PM request.",
 85→      `Intent: ${input.intent}`,
 86→      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
 87→      INTENT_INSTRUCTIONS[input.intent],
 88→      "Context:",
 89→      input.conversationContext,
 90→    ].join("\n"),
 91→  });
 92→
 93→  if (!result.output) {
 94→    throw new Error("pm agent did not produce structured output");
 95→  }
 96→
 97→  const extracted_entities: ExtractedEntity[] = [];
 98→  const extracted_relationships: ExtractedRelationship[] = [];
 99→
100→  for (const step of result.steps) {
101→    for (const toolResult of step.toolResults) {
102→      const res = toolResult.output as Record<string, unknown> | undefined;
103→      if (res) {
104→        if (Array.isArray(res.extracted_entities)) {
105→          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
106→        }
107→        if (Array.isArray(res.extracted_relationships)) {
108→          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
109→        }
110→      }
111→    }
112→  }
113→
114→  return {
115→    ...result.output,
116→    extracted_entities,
117→    extracted_relationships,
118→  };
