113→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
114→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
115→  if (!response.ok || !response.body) {
116→    throw new Error(`Failed to open SSE stream (${response.status})`);
117→  }
118→
119→  const reader = response.body.getReader();
120→  const decoder = new TextDecoder();
121→  const events: T[] = [];
122→  let buffer = "";
123→
124→  const timeout = setTimeout(() => {
125→    void reader.cancel();
126→  }, timeoutMs);
127→
128→  try {
129→    while (true) {
130→      const { value, done } = await reader.read();
131→      if (done) {
132→        break;
133→      }
134→
135→      buffer += decoder.decode(value, { stream: true });
136→      const segments = buffer.split("\n\n");
137→      buffer = segments.pop() ?? "";
138→
139→      for (const segment of segments) {
140→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
141→        if (!dataLine) {
142→          continue;
143→        }
144→
145→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
146→        events.push(event);
147→
148→        if (event.type === "error") {
149→          const errorText = (event as { error?: string }).error;
150→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
151→        }
152→
153→        if (event.type === "done") {
154→          return events;
155→        }
156→      }
157→    }
158→  } finally {
159→    clearTimeout(timeout);
160→    reader.releaseLock();
161→  }
162→
163→  return events;
164→}
165→
166→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
167→  const response = await fetch(url, init);
168→  if (!response.ok) {
169→    const body = await response.text();
170→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
171→  }
172→
173→  return (await response.json()) as T;
174→}
