123→function formatConversationEntities(entities: ConversationEntity[]): string {
124→  if (entities.length === 0) {
125→    return "- none";
126→  }
127→
128→  return entities
129→    .slice(0, 20)
130→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
131→    .join("\n");
132→}
133→
134→function formatProjectList(projects: WorkspaceProjectSummary[]): string {
135→  if (projects.length === 0) {
136→    return "- none";
137→  }
138→
139→  return projects
140→    .slice(0, 15)
141→    .map((project) => `- ${project.name} [id: ${project.id}] active tasks: ${project.activeTaskCount}`)
142→    .join("\n");
143→}
144→
145→function formatDecisionList(decisions: WorkspaceDecisionSummary[]): string {
146→  if (decisions.length === 0) {
147→    return "- none";
148→  }
149→
150→  return decisions
151→    .slice(0, 15)
152→    .map((decision) => {
153→      const project = decision.project ? ` project: ${decision.project}` : "";
154→      return `- ${decision.name} [id: ${decision.id}] status: ${decision.status}${project}`;
155→    })
156→    .join("\n");
157→}
158→
159→function formatQuestionList(questions: WorkspaceQuestionSummary[]): string {
160→  if (questions.length === 0) {
161→    return "- none";
162→  }
163→
164→  return questions
165→    .slice(0, 15)
166→    .map((question) => {
167→      const project = question.project ? ` project: ${question.project}` : "";
168→      return `- ${question.name} [id: ${question.id}]${project}`;
169→    })
170→    .join("\n");
171→}
172→
173→function formatObservationList(observations: ObservationSummary[]): string {
174→  if (observations.length === 0) {
175→    return "- none";
176→  }
177→
178→  return observations
179→    .slice(0, 10)
180→    .map((observation) => {
181→      const category = observation.category ? `, ${observation.category}` : "";
182→      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
183→    })
184→    .join("\n");
185→}
