103→export async function seedWorkspace(surreal: Surreal, workspaceName?: string, nextId?: () => string): Promise<{
104→  workspaceRecord: RecordId<"workspace", string>;
105→  workspaceName: string;
106→  projectRecord: RecordId<"project", string>;
107→  conversationRecord: RecordId<"conversation", string>;
108→  ownerPersonCount: number;
109→}> {
110→  const id = nextId ?? randomUUID;
111→  const now = new Date();
112→  const resolvedWorkspaceName = workspaceName ?? `Eval ${Date.now()}`;
113→  const workspaceRecord = new RecordId("workspace", id());
114→  const projectRecord = new RecordId("project", id());
115→  const conversationRecord = new RecordId("conversation", id());
116→  const ownerRecord = new RecordId("person", id());
117→
118→  await surreal.create(workspaceRecord).content({
119→    name: resolvedWorkspaceName,
120→    status: "active",
121→    onboarding_complete: false,
122→    onboarding_turn_count: 0,
123→    onboarding_summary_pending: false,
124→    onboarding_started_at: now,
125→    created_at: now,
126→    updated_at: now,
127→  });
128→
129→  await surreal.create(projectRecord).content({
130→    name: "Eval Project",
131→    status: "active",
132→    created_at: now,
133→    updated_at: now,
134→  });
135→
136→  // NOTE: Do NOT link default eval project to workspace via has_project.
137→  // Only workspace_seed projects should appear in workspace scope so the
138→  // extraction LLM sees the correct project list for project-vs-feature classification.
139→
140→  await surreal.create(ownerRecord).content({
141→    name: "Marcus",
142→    created_at: now,
143→    updated_at: now,
144→  });
145→
146→  await surreal.relate(ownerRecord, new RecordId("member_of", id()), workspaceRecord, {
147→    role: "owner",
148→    added_at: now,
149→  }).output("after");
150→
151→  await surreal.create(conversationRecord).content({
152→    createdAt: now,
153→    updatedAt: now,
154→    workspace: workspaceRecord,
155→    source: "onboarding",
156→  });
157→
158→  return { workspaceRecord, workspaceName: resolvedWorkspaceName, projectRecord, conversationRecord, ownerPersonCount: 1 };
159→}
