161→export async function seedConversationContext(
162→  surreal: Surreal,
163→  conversationRecord: RecordId<"conversation", string>,
164→  context: Array<{ role: "user" | "assistant"; text: string }>,
165→  nextId?: () => string,
166→): Promise<string[]> {
167→  const id = nextId ?? randomUUID;
168→  const now = Date.now();
169→  const messageIds: string[] = [];
170→  for (const [index, message] of context.entries()) {
171→    const seededMessageRecord = new RecordId("message", id());
172→    await surreal.create(seededMessageRecord).content({
173→      conversation: conversationRecord,
174→      role: message.role,
175→      text: message.text,
176→      createdAt: new Date(now + index),
