213→export async function seedGraphEntities(
214→  surreal: Surreal,
215→  workspaceRecord: RecordId<"workspace", string>,
216→  projectRecord: RecordId<"project", string>,
217→  conversationRecord: RecordId<"conversation", string>,
218→  seeds: WorkspaceSeedItem[],
219→  nextId?: () => string,
220→): Promise<void> {
221→  const id = nextId ?? randomUUID;
222→  const now = new Date();
223→  const seedMessageRecord = new RecordId("message", id());
224→  await surreal.create(seedMessageRecord).content({
225→    conversation: conversationRecord,
226→    role: "assistant",
227→    text: "Workspace seed context.",
228→    createdAt: new Date(now.getTime() - 60_000),
229→  });
230→
231→  for (const seed of seeds) {
232→    const entityRecord = new RecordId(seed.kind, id());
233→    await surreal.create(entityRecord).content(buildSeedEntityContent(seed.kind, seed.text, now));
234→
235→    await surreal.relate(seedMessageRecord, new RecordId("extraction_relation", id()), entityRecord, {
236→      confidence: 0.95,
237→      extracted_at: now,
238→      created_at: now,
239→      model: "seed",
240→      from_text: seed.text,
241→      evidence: seed.text,
242→      evidence_source: seedMessageRecord,
243→    }).output("after");
244→
245→    if (seed.kind === "feature") {
246→      await surreal.relate(projectRecord, new RecordId("has_feature", id()), entityRecord as RecordId<"feature", string>, {
247→        added_at: now,
248→      }).output("after");
249→    }
250→
251→    if (seed.kind === "task" || seed.kind === "decision" || seed.kind === "question") {
252→      await surreal.relate(entityRecord, new RecordId("belongs_to", id()), projectRecord, {
253→        added_at: now,
254→      }).output("after");
255→    }
256→
257→    if (seed.kind === "project") {
258→      await surreal.relate(workspaceRecord, new RecordId("has_project", id()), entityRecord as RecordId<"project", string>, {
259→        added_at: now,
260→      }).output("after");
261→    }
262→  }
263→}
