 25→export type ChatContext = {
 26→  conversationEntities: ConversationEntity[];
 27→  workspaceSummary: {
 28→    projects: WorkspaceProjectSummary[];
 29→    recentDecisions: WorkspaceDecisionSummary[];
 30→    openQuestions: WorkspaceQuestionSummary[];
 31→    openObservations: ObservationSummary[];
 32→  };
 33→  onboardingSummary?: string;
 34→  discussedEntity?: DiscussedEntityContext;
